import{_ as t,o as n,c as s,a3 as a}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"4. Definitions","description":"","frontmatter":{"title":"4. Definitions","eba":"Allied Health Professionals 2021-2026","topics":["leave","hours"]},"headers":[],"relativePath":"ebas/allied-health/preliminary/4-definitions.md","filePath":"ebas/allied-health/preliminary/4-definitions.md"}'),o={name:"ebas/allied-health/preliminary/4-definitions.md"};function r(i,e,l,p,h,d){return n(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="_4-definitions" tabindex="-1">4. Definitions <a class="header-anchor" href="#_4-definitions" aria-label="Permalink to &quot;4. Definitions&quot;">​</a></h1><p><strong>4.1</strong> Act means the Fair Work Act 2009 (Cth), or its successor.</p><p><strong>4.2</strong> ADO means accrued day off.</p><p><strong>4.3</strong> Adoption or Adopt for the purposes of this Agreement and the NES includes the placement of a child with an Eligible Employee (as defined in subclause 70.2(d)) prior to the relevant government department (currently the Department of Families, Fairness and Housing) seeking a permanent care order for the child.</p><p><strong>4.4</strong> Agreement means the Allied Health Professionals (Victorian Public Sector) (Single Interest Employers) Enterprise Agreement 2021-2026.</p><p><strong>4.5</strong> Award means the Health Professionals and Support Services Award 2020.</p><p><strong>4.6</strong> BPECC means the Best Practice Employment Commitment Committee established under <a href="/eba/ebas/allied-health/union-matters/84-best-practice-employment-commitment-committee-and.html">clause 84</a>.</p><p><strong>4.7</strong> Child includes an adopted child, step child and ex-nuptial child.</p><p><strong>4.8</strong> Commission means the Fair Work Commission or any successor body.</p><p><strong>4.9</strong> Department means the Department of Health, or its successor.</p><p><strong>4.10</strong> Employee means a person employed by an Employer listed in <a href="/eba/ebas/allied-health/appendices/1-list-of-employers.html">Appendix 1</a> of this Agreement who is employed in any of the classifications set out in this Agreement (see <a href="/eba/ebas/allied-health/appendices/4-classification-definitions.html">Appendix 4</a>), other than employees employed solely or predominantly in the provision of public mental health services.</p><p><strong>4.11</strong> Employer means each organisation listed in <a href="/eba/ebas/allied-health/appendices/1-list-of-employers.html">Appendix 1</a> of this Agreement.</p><p><strong>4.12</strong> EO Act means the Equal Opportunity Act 2010 (Vic).</p><p><strong>4.13</strong> Experience is as defined at subclause 85.12(a).</p><p><strong>4.14</strong> FFPPOA means the first full pay period on or after.</p><p><strong>4.15</strong> HSR means a health and safety representative (including a deputy health and safety representative).</p><p><strong>4.16</strong> Immediate Family means:</p><p><strong>(a)</strong> a Spouse, Child, parent, grandparent, grandchild or sibling of the Employee; or</p><p><strong>(b)</strong> a child, parent, grandparent, grandchild or sibling of a Spouse of the Employee.</p><p><strong>4.17</strong> Miscarriage means a spontaneous loss of an embryo or fetus before a period of gestation of 20 weeks.</p><p><strong>4.18</strong> National Employment Standards or NES means Part 2-2 of the Act as amended from time to time.</p><p><strong>4.19</strong> OHS Act means the Occupational Health and Safety Act 2004 (Vic), or its successor.</p><p><strong>4.20</strong> Registered Health Practitioner means an individual who is registered under the Health Practitioner Regulation National Law (as adopted in the applicable State or Territory) to practise a health profession, other than as a student.</p><p><strong>4.21</strong> Spouse includes a person to whom an Employee is married, a de facto partner, former spouse or former de facto spouse of the Employee. A de facto Spouse means a person who lives with the Employee as husband, wife or same-sex partner on a bona fide domestic basis.</p><p><strong>4.22</strong> Stillborn Child means:</p><p><strong>(a)</strong> a child who weighs at least 400 grams at delivery or whose period of gestation was at least 20 weeks; and</p><p><strong>(b)</strong> who has not breathed since delivery; and</p><p><strong>(c)</strong> whose heart has not beaten since delivery.</p><p><strong>4.23</strong> Union means the Health Services Union. The branch of the Health Services Union entitled to represent the Employees covered by the Agreement is the Health Services Union Victoria No. 3 Branch, trading as the Victorian Allied Health Professionals Association (VAHPA). Any obligations and entitlements of the Union under this Agreement are obligations and entitlements of the Health Services Union Victoria No. 3 Branch.</p><p><strong>4.24</strong> VHIA means the Employer’s Representative, the Victorian Hospitals’ Industrial Association.</p><p><strong>4.25</strong> WIC means Workplace Implementation Committee established under subclause 83.2.</p><p><strong>4.26</strong> WIRC Act means the Workplace Injury Rehabilitation and Compensation Act 2013 (Vic), or if applicable in the particular situation the Accident Compensation Act 1985 (Vic) or the Workers Compensation Act 1958 (Vic).</p><p><strong>4.27</strong> 2011 Agreement means the Victorian Public Health Sector (Health Professionals, Health and Allied Services, Managers and Administrative Officers) Multiple Enterprise Agreement 2011 – 2015.</p><p><strong>4.28</strong> 2016 Agreement means the Allied Health Professionals (Victorian Public Health Sector) Single Interest Enterprise Agreement 2016-2020.</p><p><strong>4.29</strong> 2020 Agreement means the Allied Health Professionals (Victorian Public Sector) (Single Interest Employers) Enterprise Agreement 2020-2021.</p><p>Plain language terms: glossary, meanings.</p>',36)])])}const g=t(o,[["render",r]]);export{c as __pageData,g as default};
